.page-content h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2.3rem;
    color: #E0E0E0;
    text-align: center;
    padding: 8px 16px;
    border: 1px solid #6C63A6;
    border-radius: 6px;
    letter-spacing: 1px;
    margin: 20px 0;
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 10px;
    width: 100%;
    box-sizing: border-box;
    overflow-y: hidden;
}

.page-content h3 {
    font-size: 2.3rem;
}

.page-content h2::before {
    content: '⌬';
    color: #6C63A6;
    font-size: 1.3em;
    transition: transform 0.6s cubic-bezier(0.25, 1, 0.5, 1);
}

.page-content h2:hover::before {
    transform: rotate(-12deg) scale(1.1);
}

.page-content h2.arg-entry::before {
    content: none !important;
}

.page-content h2.arg-entry .mw-customtoggle-arg1 {
    background: none;
    border: none;
    box-shadow: none;
    font-family: 'Playfair Display', serif;
    font-size: 1.3em;
    color: #6C63A6;
    text-align: center;
    padding: 15px 10px;
    border-radius: 6px;
    letter-spacing: 1px;
    display: inline-flex;
    justify-content: center;
    align-items: center;
    gap: 10px;
    position: relative;
    transition: transform 0.6s cubic-bezier(0.25, 1, 0.5, 1), color 0.3s ease;
}

.page-content h2.arg-entry .mw-customtoggle-arg1:hover {
    transform: rotate(-12deg) scale(1.1);
    color: #8a7dc2;
}

@keyframes glitch-flicker {
    0%, 100% {
        opacity: 1;
        transform: translate(0, 0) scale(1);
    }
    20% {
        opacity: 0.7;
        transform: translate(-1px, 1px) scale(1.05);
    }
    40% {
        opacity: 0.3;
        transform: translate(2px, -2px) scale(0.95);
    }
    60% {
        opacity: 0.9;
        transform: translate(-2px, 1px) scale(1.1);
    }
    80% {
        opacity: 0.4;
